content.text:
type SuperchargeAgentProps = {
  stats: {
    total: number;
    official: number;
    builders: number;
  };
};

export function SuperchargeAgent({ stats }: SuperchargeAgentProps) {
  return (
    <section className="ui-panel relative overflow-hidden rounded-[34px] px-6 py-8 shadow-[0_20px_48px_rgba(0,0,0,0.16)] sm:px-8 sm:py-10">
      <div className="hero-shimmer pointer-events-none absolute inset-0 opacity-70" />
      <div className="pointer-events-none absolute inset-0 bg-[radial-gradient(circle_at_top_right,rgba(255,255,255,0.08),transparent_30%),linear-gradient(180deg,rgba(255,255,255,0.03),transparent_40%)]" />
      <div className="relative space-y-6">
        <div className="flex flex-wrap items-center gap-3">
          <div className="section-kicker">Open CLI</div>
          <span className="rounded-full border border-white/10 bg-white/[0.045] px-2.5 py-1 font-mono text-[10px] uppercase tracking-[0.16em] text-white/42">
            Live directory
          </span>
        </div>

        <div className="max-w-[52rem] space-y-3">
          <h1 className="ui-title-xl max-w-[13ch] tracking-[-0.075em]">
            Choose the right CLI faster.
          </h1>
          <p className="max-w-[38rem] text-sm leading-6 text-white/46 sm:text-[15px]">
            Search by task or jump straight to a known tool.
          </p>
        </div>

        <div className="grid gap-3 sm:grid-cols-3">
          <HeroStat label="Tools indexed" value={String(stats.total)} />
          <HeroStat label="Official platforms" value={String(stats.official)} />
          <HeroStat label="Builder-made" value={String(stats.builders)} />
        </div>
      </div>
    </section>
  );
}

function HeroStat({ label, value }: { label: string; value: string }) {
  return (
    <div className="rounded-[22px] border border-white/10 bg-white/[0.035] px-4 py-3 shadow-[inset_0_1px_0_rgba(255,255,255,0.035)]">
      <div className="font-mono text-[10px] uppercase tracking-[0.16em] text-white/34">{label}</div>
      <div className="mt-2 text-2xl font-semibold tracking-[-0.04em] text-white">{value}</div>
    </div>
  );
}

* {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  min-height: 100vh;
  overflow-x: hidden;
  background:
    radial-gradient(circle at top center, rgba(132, 154, 194, 0.12), transparent 24%),
    radial-gradient(circle at 50% -10%, rgba(255, 255, 255, 0.045), transparent 28%),
    linear-gradient(180deg, rgba(255, 255, 255, 0.02), transparent 18%),
    #0b1016;
  font-family: var(--font-geist-sans), Arial, Helvetica, sans-serif;
}

body::before {
  content: "";
  position: fixed;
  inset: 0;
  pointer-events: none;
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.02), transparent 12%, transparent 88%, rgba(255, 255, 255, 0.014));
}

body::after {
  content: "";
  position: fixed;
  inset: 0;
  pointer-events: none;
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.028);
}

::selection {
  background: rgba(255, 255, 255, 0.18);
  color: white;
}

.section-kicker {
  font-family: var(--font-geist-mono), monospace;
  font-size: 11px;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.48);
}

.panel-texture {
  background-color: rgba(255, 255, 255, 0.025);
  background-image: linear-gradient(180deg, rgba(255, 255, 255, 0.03), transparent 40%);
}

a {
  text-decoration: none;
}

.ui-panel {
  border: 1px solid rgba(255, 255, 255, 0.1);
  background: #151d26;
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.02);
}

.ui-panel-soft {
  border: 1px solid rgba(255, 255, 255, 0.1);
  background: rgba(255, 255, 255, 0.05);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.03);
}

.ui-panel-faint {
  border: 1px solid rgba(255, 255, 255, 0.1);
  background: rgba(255, 255, 255, 0.03);
}

.ui-title-xl {
  color: white;
  font-weight: 600;
  letter-spacing: -0.05em;
  line-height: 0.98;
  font-size: clamp(2.5rem, 6vw, 5rem);
}

.ui-title-lg {
  color: white;
  font-weight: 600;
  letter-spacing: -0.04em;
  line-height: 1.02;
  font-size: clamp(2rem, 4vw, 3rem);
}

.ui-title-md {
  color: white;
  font-weight: 500;
  letter-spacing: -0.02em;
  line-height: 1.2;
  font-size: 1.125rem;
}

.ui-body {
  color: rgba(255, 255, 255, 0.64);
  font-size: 15px;
  line-height: 1.85;
}

.ui-body-strong {
  color: rgba(255, 255, 255, 0.74);
  font-size: 15px;
  line-height: 1.8;
}

.ui-meta {
  color: rgba(255, 255, 255, 0.56);
}

.ui-meta-faint {
  color: rgba(255, 255, 255, 0.42);
}

.ui-label {
  font-family: var(--font-geist-mono), monospace;
  font-size: 10px;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.4);
}

.ui-code {
  border: 1px solid rgba(255, 255, 255, 0.12);
  background: rgba(255, 255, 255, 0.05);
  color: rgba(255, 255, 255, 0.9);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

@keyframes marquee {
  from {
    transform: translateX(0);
  }
  to {
    transform: translateX(calc(-50% - 0.5rem));
  }
}

.marquee-track {
  animation: marquee 42s linear infinite;
  will-change: transform;
}

.marquee-track:hover {
  animation-play-state: paused;
}

/* ── Fade-in on scroll / mount ── */
@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(12px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.animate-fade-in-up {
  animation: fadeInUp 0.5s ease-out both;
}

/* stagger children */
.stagger-children > * {
  animation: fadeInUp 0.45s ease-out both;
}
.stagger-children > *:nth-child(1) { animation-delay: 0ms; }
.stagger-children > *:nth-child(2) { animation-delay: 60ms; }
.stagger-children > *:nth-child(3) { animation-delay: 120ms; }
.stagger-children > *:nth-child(4) { animation-delay: 180ms; }
.stagger-children > *:nth-child(5) { animation-delay: 240ms; }
.stagger-children > *:nth-child(6) { animation-delay: 300ms; }

/* ── Pulse ring on focus ── */
@keyframes pulseRing {
  0% { box-shadow: 0 0 0 0 rgba(255, 255, 255, 0.18); }
  70% { box-shadow: 0 0 0 6px rgba(255, 255, 255, 0); }
  100% { box-shadow: 0 0 0 0 rgba(255, 255, 255, 0); }
}

/* ── Spinner ── */
@keyframes spin {
  to { transform: rotate(360deg); }
}

.spinner {
  width: 14px;
  height: 14px;
  border: 2px solid rgba(255, 255, 255, 0.12);
  border-top-color: rgba(255, 255, 255, 0.78);
  border-radius: 50%;
  animation: spin 0.6s linear infinite;
}

/* ── Directory row glow ── */
.directory-row {
  position: relative;
  transition: background 0.2s ease, box-shadow 0.2s ease;
}

.directory-row::before {
  content: "";
  position: absolute;
  inset: 0;
  opacity: 0;
  transition: opacity 0.25s ease;
  background: linear-gradient(90deg, rgba(255, 255, 255, 0.025) 0%, rgba(255, 255, 255, 0.01) 100%);
  pointer-events: none;
}

.directory-row:hover::before {
  opacity: 1;
}

.directory-row:hover {
  box-shadow: inset 1px 0 0 rgba(255, 255, 255, 0.16);
}

/* ── Subtle shimmer for hero ── */
@keyframes shimmer {
  0% { background-position: -200% 0; }
  100% { background-position: 200% 0; }
}

.hero-shimmer {
  background: linear-gradient(
    90deg,
    transparent 0%,
    rgba(255, 255, 255, 0.03) 35%,
    rgba(255, 255, 255, 0.045) 50%,
    rgba(255, 255, 255, 0.03) 65%,
    transparent 100%
  );
  background-size: 200% 100%;
  animation: shimmer 10s ease-in-out infinite;
}

/* ── Kbd styling ── */
.kbd {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 22px;
  height: 22px;
  padding: 0 6px;
  border-radius: 5px;
  border: 1px solid rgba(255, 255, 255, 0.14);
  background: rgba(255, 255, 255, 0.07);
  font-family: var(--font-geist-mono), monospace;
  font-size: 11px;
  color: rgba(255, 255, 255, 0.58);
  line-height: 1;
  box-shadow: 0 1px 2px rgba(0, 0, 0, 0.22), inset 0 1px 0 rgba(255, 255, 255, 0.06);
}


