  --color-secondary-foreground: var(--secondary-foreground);
  --color-secondary: var(--secondary);
  --color-primary-foreground: var(--primary-foreground);
  --color-primary: var(--primary);
  --color-popover-foreground: var(--popover-foreground);
  --color-popover: var(--popover);
  --color-card-foreground: var(--card-foreground);
  --color-card: var(--card);
  --radius-sm: calc(var(--radius) * 0.6);
  --radius-md: calc(var(--radius) * 0.8);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) * 1.4);
  --radius-2xl: calc(var(--radius) * 1.8);
  --radius-3xl: calc(var(--radius) * 2.2);
  --radius-4xl: calc(var(--radius) * 2.6);
  --font-heading: var(--font-sans);
}

* {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  min-height: 100vh;
  overflow-x: hidden;
  background:
    radial-gradient(circle at top center, rgba(102, 120, 154, 0.08), transparent 22%),
    radial-gradient(circle at 50% -10%, rgba(255, 255, 255, 0.028), transparent 24%),
    linear-gradient(180deg, rgba(255, 255, 255, 0.012), transparent 16%),
    #070b10;
  font-family: var(--font-geist-sans), Arial, Helvetica, sans-serif;
}

body::before {
  content: "";
  position: fixed;
  inset: 0;
  pointer-events: none;
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.014), transparent 12%, transparent 88%, rgba(255, 255, 255, 0.01));
}

body::after {
  content: "";
  position: fixed;
  inset: 0;
  pointer-events: none;
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.028);
}

::selection {
  background: rgba(255, 255, 255, 0.18);
  color: white;
}

.section-kicker {
  font-family: var(--font-geist-mono), monospace;
  font-size: 11px;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.58);
}

.panel-texture {
  background-color: rgba(255, 255, 255, 0.025);
  background-image: linear-gradient(180deg, rgba(255, 255, 255, 0.03), transparent 40%);
}

a {
  text-decoration: none;
}

.ui-panel {
  border: 1px solid rgba(255, 255, 255, 0.1);
  background: #111821;
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.025);
}

.ui-panel-soft {
  border: 1px solid rgba(255, 255, 255, 0.1);
  background: rgba(255, 255, 255, 0.06);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.035);
}

.ui-panel-faint {
  border: 1px solid rgba(255, 255, 255, 0.1);
  background: rgba(255, 255, 255, 0.035);
}

.ui-title-xl {
  color: white;
  font-weight: 600;
  letter-spacing: -0.05em;
  line-height: 0.98;
  font-size: clamp(2.5rem, 6vw, 5rem);
}

.ui-title-lg {
  color: white;
  font-weight: 600;
  letter-spacing: -0.04em;
  line-height: 1.02;
  font-size: clamp(2rem, 4vw, 3rem);
}

.ui-title-md {
  color: white;
  font-weight: 500;
  letter-spacing: -0.02em;
  line-height: 1.2;
  font-size: 1.125rem;
}

.ui-body {
  color: rgba(255, 255, 255, 0.78);
  font-size: 15px;
  line-height: 1.85;
}

.ui-body-strong {
  color: rgba(255, 255, 255, 0.86);
  font-size: 15px;
  line-height: 1.8;
}

.ui-meta {
  color: rgba(255, 255, 255, 0.66);
}

.ui-meta-faint {
  color: rgba(255, 255, 255, 0.5);
}

.ui-label {
  font-family: var(--font-geist-mono), monospace;
  font-size: 10px;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.54);
}

.ui-code {
  border: 1px solid rgba(255, 255, 255, 0.12);
  background: rgba(255, 255, 255, 0.05);
  color: rgba(255, 255, 255, 0.9);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

@keyframes marquee {
  from {
    transform: translateX(0);
  }
  to {
    transform: translateX(calc(-50% - 0.5rem));
  }
}

.marquee-track {
  animation: marquee 42s linear infinite;
  will-change: transform;
}

.marquee-track:hover {
  animation-play-state: paused;
}

/* ── Fade-in on scroll / mount ── */
@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(12px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.animate-fade-in-up {
  animation: fadeInUp 0.5s ease-out both;
}

/* stagger children */
.stagger-children > * {
  animation: fadeInUp 0.45s ease-out both;
}
.stagger-children > *:nth-child(1) { animation-delay: 0ms; }
.stagger-children > *:nth-child(2) { animation-delay: 60ms; }
.stagger-children > *:nth-child(3) { animation-delay: 120ms; }
.stagger-children > *:nth-child(4) { animation-delay: 180ms; }
.stagger-children > *:nth-child(5) { animation-delay: 240ms; }
.stagger-children > *:nth-child(6) { animation-delay: 300ms; }

/* ── Pulse ring on focus ── */
@keyframes pulseRing {
  0% { box-shadow: 0 0 0 0 rgba(255, 255, 255, 0.18); }
  70% { box-shadow: 0 0 0 6px rgba(255, 255, 255, 0); }
  100% { box-shadow: 0 0 0 0 rgba(255, 255, 255, 0); }
}

/* ── Spinner ── */
@keyframes spin {
  to { transform: rotate(360deg); }
}

.spinner {
  width: 14px;
  height: 14px;
  border: 2px solid rgba(255, 255, 255, 0.12);
  border-top-color: rgba(255, 255, 255, 0.78);
  border-radius: 50%;
  animation: spin 0.6s linear infinite;
}

/* ── Directory row glow ── */
.directory-row {
