        transition={{ ...motionTransition, delay: HOME_REVEAL.hero }}
      >
        <SuperchargeAgent stats={directoryStats} />
      </motion.div>

      <section id="directory" className="scroll-mt-20 space-y-5">
        <motion.div
          initial={{ opacity: 0, y: 16 }}
          animate={{ opacity: 1, y: polish.search.y }}
