        <AnimatePresence mode="wait">
          {hasQuery ? (
            <RecommendationPanel
              recommendation={recommendation}
              isLoading={isLoading}
              revealY={polish.recommendation.y}
              glow={polish.recommendation.glow}
              transition={motionTransition}
