            {showCatalog ? "Hide catalog" : catalogLabel}
            <ChevronIcon className={`h-3.5 w-3.5 transition-transform ${showCatalog ? "rotate-180" : ""}`} />
          </button>
        </div>

        {showCatalog ? (
