export function SuperchargeAgent({ stats }: SuperchargeAgentProps) {
  return (
    <section className="ui-panel relative overflow-hidden rounded-[34px] px-6 py-8 shadow-[0_20px_48px_rgba(0,0,0,0.16)] sm:px-8 sm:py-10">
